Trigger.script:
if(matches[2]=="linke")then
	schale={1,0,0}
end

if(matches[2]=="mittlere")then
	schale={0,1,0}
end

if(matches[2]=="rechte")then
	schale={0,0,1}
end

display(" | "..schale[1].." |   | "..schale[2].." |   | "..schale[3].." |")

if(matches[2]=="linke") then if(matches[3]=="mittleren")then temp=schale[1] schale[1]=schale[2] schale[2]=temp end if(matches[3]=="rechten")then temp=schale[1] schale[1]=schale[3] schale[3]=temp end end
if(matches[2]=="mittlere") then if(matches[3]=="linken")then temp=schale[2] schale[2]=schale[1] schale[1]=temp end if(matches[3]=="rechten")then temp=schale[2] schale[2]=schale[3] schale[3]=temp end end
if(matches[2]=="rechte") then if(matches[3]=="mittleren")then temp=schale[3] schale[3]=schale[2] schale[2]=temp end if(matches[3]=="linken")then temp=schale[3] schale[3]=schale[1] schale[1]=temp end end display(" | "..schale[1].." | | "..schale[2].." | | "..schale[3].." |")

local zustand={}
zustand["ist absolut fit."] = 100 zustand["ist schon ein wenig schwaecher."] = 90 --Matrix zustand["fuehlte sich heute auch schon besser."] = 80 -- Matrix zustand["sieht ein wenig angekratzt aus."] = 70 -- Matrix zustand["ist deutlich angekratzt."] = 60 -- Matrix zustand["sieht recht mitgenommen aus."] = 50 -- Matrix zustand["schwankt und wankt."] = 40 -- Matrix zustand["war auch schon mal deutlich besser drauf."] = 30 -- Matrix zustand["braucht dringend aerztliche Behandlung."] = 20 -- Matrix zustand["ist schon so gut wie bei Lars."]= 10 -- Matrix
for k,v in pairs(zustand) do if string.match(matches[2], k) then Vesray.life:echo("Vesray: "..v.."%") end end

Alias.script:
multitemp = {}
for w in string.gmatch(matches[3], "%w+") do multitemp[#multitemp+1]=matches[2]..w..matches[4] end
rekursiverabbau()

FLUCHT.vorsicht=tonumber(matches[2])
FLUCHT.reaktion={matches[3]}
update_wimpy()

